changeSet.createView:
SELECT /* ── Classification comptable ────────────────────────────── */ LEFT(cpt.planComptable, 1) AS classe_compte, cpt.planComptable AS num_compte,
/* ── Rubrique bilan selon classe ─────────────────────────── */ CASE LEFT(cpt.planComptable, 1) WHEN '1' THEN 'PASSIF' WHEN '2' THEN 'ACTIF' WHEN '3' THEN 'ACTIF' WHEN '4' THEN 'ACTIF' WHEN '5' THEN 'ACTIF' ELSE 'HORS_BILAN' END AS rubrique,
/* ── Sous-rubrique descriptive ───────────────────────────── */ CASE LEFT(cpt.planComptable, 1) WHEN '1' THEN 'Capitaux propres et dettes LT' WHEN '2' THEN 'Immobilisations' WHEN '3' THEN 'Stocks' WHEN '4' THEN 'Portefeuille crédit et créances' WHEN '5' THEN 'Trésorerie' ELSE 'Charges / Produits' END AS libelle_rubrique,
/* ── Agence ──────────────────────────────────────────────── */ cpt.agence AS code_agence, ag.NOMAGENCE AS nom_agence,
/* ── Cumuls ──────────────────────────────────────────────── */ COUNT(*) AS nb_ecritures, COALESCE(SUM(cpt.DEBIT), 0) AS total_debit, COALESCE(SUM(cpt.CREDIT), 0) AS total_credit,
/* ── Solde net (positif = débiteur = ACTIF) ──────────────── */ COALESCE(SUM(cpt.DEBIT), 0) - COALESCE(SUM(cpt.CREDIT), 0) AS solde_net,
/* ── Solde ACTIF (débiteur net positif) ─────────────────── */ CASE WHEN COALESCE(SUM(cpt.DEBIT), 0) > COALESCE(SUM(cpt.CREDIT), 0) THEN COALESCE(SUM(cpt.DEBIT), 0) - COALESCE(SUM(cpt.CREDIT), 0) ELSE 0 END AS montant_actif,
/* ── Solde PASSIF (créditeur net positif) ────────────────── */ CASE WHEN COALESCE(SUM(cpt.CREDIT), 0) > COALESCE(SUM(cpt.DEBIT), 0) THEN COALESCE(SUM(cpt.CREDIT), 0) - COALESCE(SUM(cpt.DEBIT), 0) ELSE 0 END AS montant_passif,
/* ── Fenêtre temporelle ──────────────────────────────────── */ MIN(cpt.DATEOPERATION) AS date_premiere_ecriture, MAX(cpt.DATEOPERATION) AS date_derniere_ecriture
FROM comptabilite cpt
LEFT JOIN AGENCE ag ON ag.CODE_AGENCE = cpt.agence
WHERE cpt.planComptable IS NOT NULL AND LEFT(cpt.planComptable, 1) IN ('1','2','3','4','5')
GROUP BY LEFT(cpt.planComptable, 1), cpt.planComptable, cpt.agence, ag.NOMAGENCE
